// Mobb daemon shim — checks if daemon is alive, spawns if dead.
// Auto-generated by mobbdev CLI. Do not edit.
var fs = require('fs')
var spawn = require('child_process').spawn
var path = require('path')
var os = require('os')

var pidFile = path.join(os.homedir(), '.mobbdev', 'daemon.pid')
var HEARTBEAT_STALE_MS = __HEARTBEAT_STALE_MS__

try {
  var data = JSON.parse(fs.readFileSync(pidFile, 'utf8'))
  if (Date.now() - data.heartbeat > HEARTBEAT_STALE_MS) throw new Error('stale')
  process.kill(data.pid, 0) // throws ESRCH if the process is gone
} catch (e) {
  var localCli = process.env.MOBBDEV_LOCAL_CLI
  var child = localCli
    ? spawn('node', [localCli, 'claude-code-daemon'], { detached: true, stdio: 'ignore', windowsHide: true })
    : spawn('npx', ['--yes', 'mobbdev@latest', 'claude-code-daemon'], { detached: true, stdio: 'ignore', shell: true, windowsHide: true })
  child.unref()
}
